stepxmp.codeblock:
// Test 1: Verify status code
pm.test("Status code is 200", function () {
    pm.response.to.have.status(200);
});

// Test 2: Verify Content-Type header
pm.test("Content-Type is JSON", function () {
    pm.expect(pm.response.headers.get("Content-Type"))
      .to.include("application/json");
});

// Test 3: Verify response body field
pm.test("User name is correct", function () {
    const responseBody = pm.response.json();
    pm.expect(responseBody.name).to.eql("Jane Smith");
});

// Test 4: Response time under 500ms
pm.test("Response time is acceptable", function () {
    pm.expect(pm.response.responseTime).to.be.below(500);
});
